#!/bin/bash\n\n# Configuration\nUSER_AGENT=\"Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36\"\nCOOKIE_FILE=\"/tmp/rrx_hotspot_cookies.txt\"\nINITIAL_CHECK_URL=\"http://detectportal.firefox.com/success.txt\"\n\necho \"Starting RRX_Hotspot_portal_iob login script...\"\necho \"User-Agent: $USER_AGENT\"\necho \"Cookie File: $COOKIE_FILE\"\n\n# --- Step 1: Initial connectivity check and capture the first redirect ---\necho \"\"\necho \"--- Step 1: Initial connectivity check and capture the first redirect ---\"\necho \"Attempting to access a known external URL to trigger captive portal redirect...\"\necho \"Requesting URL: $INITIAL_CHECK_URL\"\nFIRST_REDIRECT_RESPONSE=$(curl -v -L -A \"$USER_AGENT\" -c \"$COOKIE_FILE\" \"$INITIAL_CHECK_URL\" 2>&1)\nEXIT_CODE=$?\n\nif [ $EXIT_CODE -ne 0 ]; then\n    echo \"ERROR: Curl failed during initial redirect step with exit code $EXIT_CODE.\"\n    echo \"$FIRST_REDIRECT_RESPONSE\"\n    echo \"Script aborted.\"\n    exit 1\nfi\n\n# Extract the final effective URL after all redirects\nEFFECTIVE_URL=$(echo \"$FIRST_REDIRECT_RESPONSE\" | grep -E '^< Location: ' | tail -n 1 | awk '{print $3}' | tr -d '\r')\nif [ -z \"$EFFECTIVE_URL\" ]; then\n    # Fallback to Last-Request-URL if Location header is not reliably captured (e.g., direct 200 OK after some redirects)\n    EFFECTIVE_URL=$(echo \"$FIRST_REDIRECT_RESPONSE\" | grep -E '^\* Last-Request-URL: ' | tail -n 1 | cut -d ' ' -f 3)\n    if [ -z \"$EFFECTIVE_URL\" ]; then\n        echo \"ERROR: Could not determine the effective URL after initial redirect. No Location header or Last-Request-URL found.\"\n        echo \"Full curl output:\"\n        echo \"$FIRST_REDIRECT_RESPONSE\"\n        echo \"Script aborted.\"\n        exit 1\n    fi\nfi\necho \"Initial effective URL after redirect: $EFFECTIVE_URL\"\n\n# The effective URL should contain the 'loginurl' parameter\nLOGIN_URL_PARAM=$(echo \"$EFFECTIVE_URL\" | grep -oP 'loginurl=\K[^&]*')\n\nif [ -z \"$LOGIN_URL_PARAM\" ]; then\n    echo \"ERROR: 'loginurl' parameter not found in the initial redirect URL.\"\n    echo \"Effective URL: $EFFECTIVE_URL\"\n    echo \"Full curl output:\"\n    echo \"$FIRST_REDIRECT_RESPONSE\"\n    echo \"Script aborted.\"\n    exit 1\nfi\necho \"Extracted URL-encoded loginurl parameter: $LOGIN_URL_PARAM\"\n\n# --- Step 2: URL decode the loginurl and extract Hotsplots parameters ---\necho \"\"\necho \"--- Step 2: URL decode the loginurl and extract Hotsplots parameters ---\"\n# Bash doesn't have a native URL decode. Use Python or a series of sed/printf.\nDECODED_LOGIN_URL=$(python -c \"import urllib.parse; print(urllib.parse.unquote(\"$LOGIN_URL_PARAM\"))\")\nEXIT_CODE=$?\nif [ $EXIT_CODE -ne 0 ]; then\n    echo \"WARNING: Python not found or failed to URL decode. Attempting with sed/printf (less robust). Please ensure python3 is available for robust URL decoding.\"\n    # Basic URL decode for known characters and double-encoded parts (e.g., %253D for '=')\n    DECODED_LOGIN_URL=$(echo \"$LOGIN_URL_PARAM\" | sed 's/%253A/:/g; s/%252F/\//g; s/%253F/?/g; s/%2526/\&/g; s/%253D/=/g; s/%3A/:/g; s/%2F/\//g; s/%3F/?/g; s/%26/\&/g; s/%3D/=/g')\nfi\n\nif [ -z \"$DECODED_LOGIN_URL\" ]; then\n    echo \"ERROR: Failed to URL decode the loginurl parameter.\"\n    echo \"Encoded loginurl: $LOGIN_URL_PARAM\"\n    echo \"Script aborted.\"\n    exit 1\nfi\necho \"Decoded Hotsplots login URL: $DECODED_LOGIN_URL\"\n\n# Extract parameters from the DECODED_LOGIN_URL\nQUERY_STRING=$(echo \"$DECODED_LOGIN_URL\" | grep -o '?.*' | cut -c 2-)\nif [ -z \"$QUERY_STRING\" ]; then\n    echo \"ERROR: No query string found in the decoded Hotsplots login URL.\"\n    echo \"Decoded URL: $DECODED_LOGIN_URL\"\n    echo \"Script aborted.\"\n    exit 1\nfi\necho \"Extracted query string from Hotsplots URL: $QUERY_STRING\"\n\nUAM_IP=$(echo \"$QUERY_STRING\" | grep -oP 'uamip=\K[^&]*')\nUAM_PORT=$(echo \"$QUERY_STRING\" | grep -oP 'uamport=\K[^&]*')\nCHALLENGE=$(echo \"$QUERY_STRING\" | grep -oP 'challenge=\K[^&]*')\nCALLED_MAC=$(echo \"$QUERY_STRING\" | grep -oP 'called=\K[^&]*')\nCLIENT_MAC=$(echo \"$QUERY_STRING\" | grep -oP 'mac=\K[^&]*')\nCLIENT_IP=$(echo \"$QUERY_STRING\" | grep -oP 'ip=\K[^&]*')\nNAS_ID=$(echo \"$QUERY_STRING\" | grep -oP 'nasid=\K[^&]*')\nSESSION_ID=$(echo \"$QUERY_STRING\" | grep -oP 'sessionid=\K[^&]*')\nUSER_URL=$(echo \"$QUERY_STRING\" | grep -oP 'userurl=\K[^&]*')\n\nif [ -z \"$UAM_IP\" ] || [ -z \"$CHALLENGE\" ] || [ -z \"$CLIENT_MAC\" ] || [ -z \"$SESSION_ID\" ]; then\n    echo \"ERROR: Missing one or more critical parameters from the Hotsplots login URL.\"\n    echo \"UAM_IP: $UAM_IP, CHALLENGE: $CHALLENGE, CLIENT_MAC: $CLIENT_MAC, SESSION_ID: $SESSION_ID\"\n    echo \"Script aborted.\"\n    exit 1\nfi\n\necho \"Extracted parameters:\"\necho \"  UAM_IP: $UAM_IP\"\necho \"  UAM_PORT: $UAM_PORT\"\necho \"  CHALLENGE: $CHALLENGE\"\necho \"  CALLED_MAC: $CALLED_MAC\"\necho \"  CLIENT_MAC: $CLIENT_MAC\"\necho \"  CLIENT_IP: $CLIENT_IP\"\necho \"  NAS_ID: $NAS_ID\"\necho \"  SESSION_ID: $SESSION_ID\"\necho \"  USER_URL: $USER_URL\"\n\nHOTSPLOTS_BASE_URL=$(echo \"$DECODED_LOGIN_URL\" | cut -d '?' -f 1)\necho \"Hotsplots base login URL: $HOTSPLOTS_BASE_URL\"\n\n# --- Step 3: Access the \"Online gehen\" (prelogin) URL and follow redirects to Hotsplots ---\necho \"\"\necho \"--- Step 3: Access the \"Online gehen\" (prelogin) URL ---\"\nPRELOGIN_URL=\"http://${UAM_IP}/prelogin\"\necho \"Requesting prelogin URL: $PRELOGIN_URL\"\nPRELOGIN_RESPONSE=$(curl -v -L -A \"$USER_AGENT\" -b \"$COOKIE_FILE\" -c \"$COOKIE_FILE\" \"$PRELOGIN_URL\" 2>&1)\nEXIT_CODE=$?\n\nif [ $EXIT_CODE -ne 0 ]; then\n    echo \"ERROR: Curl failed during prelogin step with exit code $EXIT_CODE.\"\n    echo \"$PRELOGIN_RESPONSE\"\n    echo \"Script aborted.\"\n    exit 1\nfi\n\nHOTSPLOTS_LOGIN_GET_URL=$(echo \"$PRELOGIN_RESPONSE\" | grep -E '^\* Last-Request-URL: ' | tail -n 1 | cut -d ' ' -f 3)\nif [ -z \"$HOTSPLOTS_LOGIN_GET_URL\" ]; then\n    echo \"ERROR: Could not determine the final Hotsplots GET URL after prelogin redirect.\"\n    echo \"Full curl output:\"\n    echo \"$PRELOGIN_RESPONSE\"\n    echo \"Script aborted.\"\n    exit 1\nfi\necho \"Final Hotsplots GET URL after prelogin redirect: $HOTSPLOTS_LOGIN_GET_URL\"\n\n# --- Step 4: Perform Hotsplots login (POST request) ---\necho \"\"\necho \"--- Step 4: Performing Hotsplots login (POST request) ---\"\necho \"Assuming a simple click-through/accept terms type of login for Hotsplots free Wi-Fi.\"\n\n# Construct POST data. Common for Hotsplots free access without credentials is 'login=1'\n# We include all parameters passed initially via the query string, re-encoding if necessary.\nHOTSPLOTS_POST_DATA=\"uamip=${UAM_IP}&uamport=${UAM_PORT}&challenge=${CHALLENGE}&called=${CALLED_MAC}&mac=${CLIENT_MAC}&ip=${CLIENT_IP}&nasid=${NAS_ID}&sessionid=${SESSION_ID}&userurl=${USER_URL}&login=1\"\n\necho \"Hotsplots POST Data: $HOTSPLOTS_POST_DATA\"\necho \"Submitting POST request to: $HOTSPLOTS_LOGIN_GET_URL\"\n\nHOTSPLOTS_LOGIN_POST_RESPONSE=$(curl -v -L -A \"$USER_AGENT\" -b \"$COOKIE_FILE\" -c \"$COOKIE_FILE\" -X POST -d \"$HOTSPLOTS_POST_DATA\" \"$HOTSPLOTS_LOGIN_GET_URL\" 2>&1)\nEXIT_CODE=$?\n\nif [ $EXIT_CODE -ne 0 ]; then\n    echo \"ERROR: Curl failed during Hotsplots POST login step with exit code $EXIT_CODE.\"\n    echo \"$HOTSPLOTS_LOGIN_POST_RESPONSE\"\n    echo \"Script aborted.\"\n    exit 1\nfi\n\necho \"Hotsplots POST login response received. Reviewing output for success indicators.\"\necho \"Full curl output from POST login:\"\necho \"$HOTSPLOTS_LOGIN_POST_RESPONSE\"\n\n# Check for successful login indicator (e.g., redirect away from login page, or success message)\nFINAL_EFFECTIVE_URL=$(echo \"$HOTSPLOTS_LOGIN_POST_RESPONSE\" | grep -E '^\* Last-Request-URL: ' | tail -n 1 | cut -d ' ' -f 3)\necho \"Final effective URL after Hotsplots POST login: $FINAL_EFFECTIVE_URL\"\n\nif echo \"$HOTSPLOTS_LOGIN_POST_RESPONSE\" | grep -qi \"login_succeeded\"; then\n    echo \"INFO: 'login_succeeded' detected in response. Login likely successful.\"\nelif echo \"$FINAL_EFFECTIVE_URL\" | grep -qv \"hotsplots.de\"; then\n    echo \"INFO: Redirected away from hotsplots.de, likely indicating successful login.\"\nelse\n    echo \"WARNING: No clear success indicator found after Hotsplots POST. Further investigation might be needed.\"\n    echo \"However, we will proceed to connectivity check.\"\nfi\n\n\n# --- Step 5: Final connectivity check ---\necho \"\"\necho \"--- Step 5: Final connectivity check ---\"\necho \"Attempting to ping 8.8.8.8 to verify internet connectivity...\"\nping -c 3 8.8.8.8 >/dev/null\nif [ $? -eq 0 ]; then\n    echo \"SUCCESS: Internet connectivity confirmed. You are online!\"\n    exit 0\nelse\n    echo \"FAILURE: Could not ping 8.8.8.8. Internet connectivity not established.\"\n    exit 1\nfi\n